mapper.select:
select bno
from member
where id = #{id}

select *
from store_member
where store_id = #{storeId}
  and member_bno = #{memberBno}
  and chk = 1
limit 1

select *
from store_member
where store_id = #{storeId}
  and member_bno = #{memberBno}
order by store_member_id desc
limit 1

select count(*)
from fill_apply
where fill_bno = #{fillBno}
  and id = #{id}
  and chk in (0, 1, 2)

select fa.*
from fill_apply fa
join fill f on f.bno = fa.fill_bno
join store s on s.store_code = f.code
where s.store_id = #{storeId}
  and fa.fill_bno = #{fillBno}
  and fa.bno = #{applyBno}
limit 1

mapper.update:
update fill
set chk = #{chk}
where bno = #{fillBno}

update fill_apply
set chk = #{chk}
where bno = #{applyBno}

update fill_apply
set chk = #{chk}
where fill_bno = #{fillBno}
  and bno != #{winnerApplyBno}
  and chk = 0

update fill_apply
set chk = 3
where fill_bno = #{fillBno}
  and id = #{id}
  and chk = 0

mapper.select:
select count(*)
from schedule sc
join store_member sm on sm.store_member_id = sc.store_employee_bno
where sm.store_id = #{storeId}
  and sc.store_employee_bno = #{storeMemberId}
  and sc.work_date = #{workDate}
  and not (sc.end_time <= #{startTime} or sc.start_time >= #{endTime})

  	and sc.bno != #{excludeScheduleBno}

mapper.update:
update schedule sc
join store_member sm_target on sm_target.store_member_id = #{storeMemberId}
join store_member sm_owner on sm_owner.store_member_id = sc.store_employee_bno
set sc.store_employee_bno = sm_target.store_member_id
where sc.bno = #{scheduleBno}
  and sm_owner.store_id = #{storeId}
  and sm_owner.position = '직원'
  and sm_target.store_id = #{storeId}
  and sm_target.position = '직원'
  and sm_target.chk = 1
